```typescript
// in exportmatching.tsx

// Refactoring the export logic to consolidate orders
useEffect(() => {
    if (isOpen && ordersToExport.length > 0 && status === 'pending') {
        const runBatchExport = async () => {
            setStatus('exporting');
            setMessage('Consolidating orders...');

            try {
                // Consolidate items
                const consolidatedItems = new Map<string, { barcode: string; quantity: number }>();
                ordersToExport.forEach(order => {
                    order.items.forEach(item => {
                        const barcode = item.barcode;
                        if (consolidatedItems.has(barcode)) {
                            const existingItem = consolidatedItems.get(barcode)!;
                            consolidatedItems.set(barcode, { ...existingItem, quantity: existingItem.quantity + item.quantity });
                        } else {
                            consolidatedItems.set(barcode, { barcode: item.barcode, quantity: item.quantity });
                        }
                    });
                });

                // Consolidate order numbers and party names
                const orderNumbers = new Set<string>();
                const partyNames = new Set<string>();
                ordersToExport.forEach(order => {
                    orderNumbers.add(order.orderNumber);
                    partyNames.add(order.partyName);
                });
                const orderNumbersString = Array.from(orderNumbers).join(',');
                const partyNamesString = Array.from(partyNames).join(',');

                // Create and send the payload
                const payload = {
                    orderNumbers: orderNumbersString,
                    partyNames: partyNamesString,
                    items: Array.from(consolidatedItems.values())
                };

                const response = await fetch('/api/export', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(payload)
                });

                if (!response.ok) {
                    throw new Error(`Export failed: ${response.status} - ${response.statusText}`);
                }

                setStatus('success');
                setMessage('Export successful');
                // Optional: Trigger download logic here
            } catch (error: any) {
                setStatus('error');
                setMessage(`Export failed: ${error.message}`);
            }
        };

        runBatchExport();
    }
}, [isOpen, ordersToExport, status]);

